class Solution {
    public int numPairsDivisibleBy60(int[] time) {
        int[] count = new int[60];
        int pairs = 0;
        for (int t : time) {
            int remainder = t % 60;
            pairs += count[(60 - remainder) % 60];
            count[remainder]++;
        }
        return pairs;
    }
}
